"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { getAnalytics } from "@/services/analytics.service";
import { getOrders } from "@/services/orders.service";
import type { AnalyticsSummary, Order } from "@/types";
import Card from "@/components/ui/Card";
import Spinner from "@/components/ui/Spinner";
import EmptyState from "@/components/ui/EmptyState";
import Badge from "@/components/ui/Badge";
import SavingsTrendChart from "@/components/charts/SavingsTrendChart";
import BoxUsageChart from "@/components/charts/BoxUsageChart";
import { formatCurrency, formatPercentage, formatDate } from "@/lib/utils";
import { TrendingUp, Package, DollarSign, Gauge, RefreshCw, Zap, ArrowUpRight, Clock } from "lucide-react";

const statusVariant: Record<string, "warning" | "success" | "danger" | "info" | "purple"> = {
  pending: "warning",
  optimized: "success",
  failed: "danger",
  no_savings: "info",
};

export default function DashboardPage() {
  const router = useRouter();
  const [analytics, setAnalytics] = useState<AnalyticsSummary | null>(null);
  const [recentOrders, setRecentOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [refreshing, setRefreshing] = useState(false);

  const fetchData = async () => {
    setRefreshing(true);
    try {
      setError(null);
      const [analyticsData, ordersData] = await Promise.all([
        getAnalytics(),
        getOrders(),
      ]);
      setAnalytics(analyticsData);
      setRecentOrders(ordersData.slice(-10).reverse());
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : "Failed to load dashboard data";
      setError(msg);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 10000);
    return () => clearInterval(interval);
  }, []);

  if (loading) {
    return (
      <div className="flex h-96 items-center justify-center">
        <Spinner size="lg" />
      </div>
    );
  }

  if (error) {
    return (
      <EmptyState
        title="Failed to load dashboard"
        description={error}
        action={
          <button onClick={fetchData} className="text-sm text-accent hover:underline">
            Retry
          </button>
        }
      />
    );
  }

  if (!analytics) {
    return (
      <EmptyState
        title="No data available"
        description="Connect the backend to see analytics"
      />
    );
  }

  const pendingCount = recentOrders.filter(o => o.status === "pending").length;

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="font-display text-xl font-black text-foreground tracking-tight">Overview</h2>
          <div className="flex items-center gap-2 mt-1">
            <span className="w-1.5 h-1.5 rounded-full bg-accent-green animate-pulse-custom" />
            <p className="text-[12px] text-muted-dark">Real-time packaging performance</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={fetchData}
            disabled={refreshing}
            className="flex items-center gap-1.5 rounded-full border border-border px-4 py-2 text-[12px] font-semibold text-muted hover:text-foreground hover:border-border2 transition-all"
          >
            <RefreshCw className={`h-3.5 w-3.5 ${refreshing ? "animate-spin" : ""}`} />
            Refresh
          </button>
          <button
            onClick={() => router.push("/optimization")}
            className="btn-primary flex items-center gap-1.5 rounded-full bg-accent px-4 py-2 text-[12px] font-semibold text-ink hover:bg-[#d8ff20] hover:shadow-[0_4px_20px_rgba(200,255,0,.25)] transition-all"
          >
            <Zap className="h-3.5 w-3.5" />
            Optimize
          </button>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
        <Card hover gradient className="group">
          <div className="absolute top-0 right-0 w-24 h-24 bg-accent/5 rounded-full blur-2xl -translate-y-6 translate-x-6 group-hover:bg-accent/10 transition-all" />
          <div className="flex items-center justify-between mb-4 relative">
            <div className="w-10 h-10 rounded-xl bg-accent/10 border border-accent/20 flex items-center justify-center">
              <Package className="h-5 w-5 text-accent" />
            </div>
            <Badge variant="warning">{pendingCount} pending</Badge>
          </div>
          <div className="font-display text-[28px] font-black tracking-tight leading-none relative z-10">
            {analytics.total_orders}
          </div>
          <div className="text-[10px] text-muted-dark uppercase tracking-wider mt-1.5 relative z-10">Orders optimized</div>
        </Card>

        <Card hover gradient className="group overflow-hidden">
          <div className="absolute top-0 right-0 w-24 h-24 bg-teal/10 rounded-full blur-2xl -translate-y-6 translate-x-6 group-hover:bg-teal/20 transition-all" />
          <div className="flex items-center justify-between mb-4 relative z-10">
            <div className="w-10 h-10 rounded-xl bg-teal/10 border border-teal/20 flex items-center justify-center">
              <DollarSign className="h-5 w-5 text-teal" />
            </div>
            <Badge variant="success">Today</Badge>
          </div>
          <div className="font-display text-[28px] font-black tracking-tight leading-none text-teal relative z-10">
            {formatCurrency(analytics.today_savings)}
          </div>
          <div className="text-[10px] text-muted-dark uppercase tracking-wider mt-1.5 relative z-10">Today's Savings</div>
        </Card>

        <Card hover gradient className="group overflow-hidden">
          <div className="absolute top-0 right-0 w-24 h-24 bg-purple/5 rounded-full blur-2xl -translate-y-6 translate-x-6 group-hover:bg-purple/10 transition-all" />
          <div className="flex items-center justify-between mb-4 relative z-10">
            <div className="w-10 h-10 rounded-xl bg-purple/10 border border-purple/20 flex items-center justify-center">
              <Gauge className="h-5 w-5 text-purple" />
            </div>
            <span className="text-[10px] font-bold text-accent bg-accent/10 px-2.5 py-1 rounded-full">
              ↑5%
            </span>
          </div>
          <div className="font-display text-[28px] font-black tracking-tight leading-none text-purple relative z-10">
            {formatPercentage(analytics.avg_efficiency)}
          </div>
          <div className="text-[10px] text-muted-dark uppercase tracking-wider mt-1.5 relative z-10">Avg efficiency</div>
        </Card>

        <Card hover gradient className="group overflow-hidden">
          <div className="absolute top-0 right-0 w-24 h-24 bg-blue/5 rounded-full blur-2xl -translate-y-6 translate-x-6 group-hover:bg-blue/10 transition-all" />
          <div className="flex items-center justify-between mb-4 relative z-10">
            <div className="w-10 h-10 rounded-xl bg-blue/10 border border-blue/20 flex items-center justify-center">
              <Zap className="h-5 w-5 text-blue" />
            </div>
          </div>
          <div className="font-display text-[28px] font-black tracking-tight leading-none text-blue relative z-10">
            {formatCurrency(analytics.total_savings)}
          </div>
          <div className="text-[10px] text-muted-dark uppercase tracking-wider mt-1.5 relative z-10">Total Savings (est.)</div>
        </Card>
      </div>

      {/* Charts */}
      <div className="grid gap-4 lg:grid-cols-2">
        <Card hover>
          <div className="mb-4">
            <div className="flex items-center gap-2">
              <TrendingUp className="h-4 w-4 text-teal" />
              <div className="text-[13px] font-semibold text-foreground">Efficiency trend</div>
            </div>
            <div className="text-[10px] text-muted-dark mt-0.5">Per order — live</div>
          </div>
          <SavingsTrendChart data={analytics.savings_trend} />
        </Card>
        <Card hover>
          <div className="mb-4">
            <div className="flex items-center gap-2">
              <Package className="h-4 w-4 text-purple" />
              <div className="text-[13px] font-semibold text-foreground">Box distribution</div>
            </div>
            <div className="text-[10px] text-muted-dark mt-0.5">Usage share</div>
          </div>
          <BoxUsageChart data={analytics.box_usage} />
        </Card>
      </div>

      {/* Recent Orders */}
      <Card hover>
        <div className="mb-4 flex items-center justify-between">
          <div>
            <div className="flex items-center gap-2">
              <Clock className="h-4 w-4 text-accent" />
              <div className="text-[13px] font-semibold text-foreground">Orders processed</div>
            </div>
            <div className="text-[10px] text-muted-dark mt-0.5">Last 14 days — live from API</div>
          </div>
          <button
            onClick={() => router.push("/orders")}
            className="text-[11px] text-accent hover:underline font-semibold flex items-center gap-1"
          >
            View all
            <ArrowUpRight className="h-3 w-3" />
          </button>
        </div>
        {recentOrders.length === 0 ? (
          <p className="py-8 text-center text-sm text-muted">No orders yet</p>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
              <thead>
                <tr className="border-b border-border">
                  <th className="pb-3 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Order</th>
                  <th className="pb-3 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Zone</th>
                  <th className="pb-3 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Status</th>
                  <th className="pb-3 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Date</th>
                </tr>
              </thead>
              <tbody>
                {recentOrders.map((order) => (
                  <tr key={order.id} className="border-b border-border/50 table-row-hover transition-colors">
                    <td className="py-3 font-mono text-[12px] text-accent">#{order.id}</td>
                    <td className="py-3 text-foreground">{order.shipping_zone}</td>
                    <td className="py-3">
                      <Badge variant={statusVariant[order.status] || "default"}>
                        {order.status}
                      </Badge>
                    </td>
                    <td className="py-3 text-muted text-[12px]">{formatDate(order.created_at)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </Card>
    </div>
  );
}

"use client";

import { useEffect, useState, useRef, useCallback } from "react";
import { useSearchParams } from "next/navigation";
import { useOrders } from "@/hooks/useOrders";
import { useOptimization } from "@/hooks/useOptimization";
import { getOrderOptimizationStatus } from "@/services/orders.service";
import Button from "@/components/ui/Button";
import Spinner from "@/components/ui/Spinner";
import EmptyState from "@/components/ui/EmptyState";
import Card from "@/components/ui/Card";
import Badge from "@/components/ui/Badge";
import { useAppContext } from "@/context/AppContext";
import {
  Zap, RotateCcw, RefreshCw, CheckCircle, Loader2, Package,
  TrendingUp, Info, Rotate3D, ChevronDown, ChevronUp, DollarSign,
  Box, ArrowRight, AlertTriangle, XCircle, Clock
} from "lucide-react";
import type { OptimizationResult } from "@/types";
import dynamic from "next/dynamic";
import api from "@/services/api";

const ThreeDPackViewer = dynamic(
  () => import("@/components/optimization/ThreeDPackViewer"),
  { ssr: false, loading: () => <div className="h-[400px] bg-[#0a0a14] rounded-xl flex items-center justify-center text-gray-500 text-sm border border-border">Loading 3D viewer...</div> }
);

interface BoxInfo {
  name: string;
  length_cm: number;
  width_cm: number;
  height_cm: number;
  max_weight_kg: number;
  supports_fragile: boolean;
}

interface ExtendedResult extends OptimizationResult {
  status: string;
  updated_at: string | null;
  boxInfo?: BoxInfo;
}

export default function OptimizationPage() {
  const searchParams = useSearchParams();
  const preselectedOrder = searchParams.get("order");
  const { orders, loading: ordersLoading, refetch } = useOrders();
  const { result: currentResult, loading: optLoading, error: optError, runOptimization, reset } = useOptimization();
  const { addToast } = useAppContext();
  const [selectedOrder, setSelectedOrder] = useState<number>(preselectedOrder ? Number(preselectedOrder) : 0);
  const [statusFilter, setStatusFilter] = useState<string>("pending");
  const [completedResults, setCompletedResults] = useState<Map<number, ExtendedResult>>(new Map());
  const [expandedOrders, setExpandedOrders] = useState<Set<number>>(new Set());
  const [show3DFor, setShow3DFor] = useState<number | null>(null);
  const [boxes, setBoxes] = useState<BoxInfo[]>([]);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const pollingRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const pollingOrderIdsRef = useRef<Set<number>>(new Set());

  useEffect(() => {
    api.get("/inventory")
      .then(res => setBoxes(res.data))
      .catch(() => {});
  }, []);

  const pollCompletedOrders = useCallback(async () => {
    const pendingIds = Array.from(pollingOrderIdsRef.current);
    if (pendingIds.length === 0) return;

    const newResults = new Map(completedResults);
    let changed = false;

    for (const orderId of pendingIds) {
      if (completedResults.has(orderId)) continue;
      try {
        const data = await getOrderOptimizationStatus(orderId);
        if (data.status === "optimized" || data.status === "no_savings" || data.status === "failed") {
          const box = boxes.find(b => b.name === data.recommended_box);
          newResults.set(orderId, {
            ...data,
            boxInfo: box,
          } as ExtendedResult);
          pollingOrderIdsRef.current.delete(orderId);
          changed = true;
        }
      } catch {
        // still running
      }
    }

    if (changed) {
      setCompletedResults(newResults);
    }

    if (pollingOrderIdsRef.current.size === 0 && pollingRef.current) {
      clearInterval(pollingRef.current);
      pollingRef.current = null;
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [boxes]);

  useEffect(() => {
    const orderIdsToTrack = orders
      .filter(o => (o.status === "optimized" || o.status === "no_savings") && !completedResults.has(o.id))
      .map(o => o.id);

    if (orderIdsToTrack.length > 0) {
      orderIdsToTrack.forEach(id => pollingOrderIdsRef.current.add(id));

      if (!pollingRef.current) {
        pollingRef.current = setInterval(pollCompletedOrders, 2000);
      }
    }
  }, [orders]);

  useEffect(() => {
    if (preselectedOrder) {
      setSelectedOrder(Number(preselectedOrder));
    }
  }, [preselectedOrder]);

  useEffect(() => {
    return () => {
      if (pollingRef.current) clearInterval(pollingRef.current);
    };
  }, []);

  const pendingOrders = orders.filter((o) => o.status === "pending");
  const completedOrders = orders.filter((o) => o.status === "optimized");
  const failedOrders = orders.filter((o) => o.status === "failed");
  const noSavingsOrders = orders.filter((o) => o.status === "no_savings");

  const handleOptimize = async () => {
    if (!selectedOrder) return;

    try {
      const data = await runOptimization(selectedOrder);
      const box = boxes.find(b => b.name === data.recommended_box);
      const extendedResult: ExtendedResult = {
        ...data,
        status: "optimized",
        updated_at: new Date().toISOString(),
        boxInfo: box,
      };

      setCompletedResults(prev => new Map(prev).set(selectedOrder, extendedResult));
      setExpandedOrders(prev => new Set(prev).add(selectedOrder));
      addToast(`Optimization complete — Saved Rs.${data.savings.toFixed(2)}`, "success");
      refetch();
    } catch {
      addToast("Optimization failed", "error");
    }
  };

  const handleReset = () => {
    reset();
    setSelectedOrder(0);
  };

  const handleViewCompleted = async (orderId: number) => {
    const cached = completedResults.get(orderId);
    if (cached) {
      setExpandedOrders(prev => {
        const next = new Set(prev);
        if (next.has(orderId)) next.delete(orderId);
        else next.add(orderId);
        return next;
      });
      return;
    }

    try {
      const data = await getOrderOptimizationStatus(orderId);
      const box = boxes.find(b => b.name === data.recommended_box);
      const extendedResult: ExtendedResult = {
        ...data,
        boxInfo: box,
      };
      setCompletedResults(prev => new Map(prev).set(orderId, extendedResult));
      setExpandedOrders(prev => new Set(prev).add(orderId));
    } catch {
      addToast("Failed to load optimization result", "error");
    }
  };

  const toggleExpand = (orderId: number) => {
    setExpandedOrders(prev => {
      const next = new Set(prev);
      if (next.has(orderId)) {
        next.delete(orderId);
        setShow3DFor(null);
      } else {
        next.add(orderId);
      }
      return next;
    });
  };

  const toggle3D = (orderId: number) => {
    setShow3DFor(prev => prev === orderId ? null : orderId);
  };

  if (ordersLoading) {
    return (
      <div className="flex h-96 items-center justify-center">
        <Spinner size="lg" />
      </div>
    );
  }

  const filterOptions = [
    { key: "pending", label: "Pending", count: pendingOrders.length, icon: Clock, color: "text-accent" },
    { key: "completed", label: "Optimized", count: completedOrders.length, icon: CheckCircle, color: "text-teal" },
    { key: "no_savings", label: "No Savings", count: noSavingsOrders.length, icon: AlertTriangle, color: "text-orange" },
    { key: "failed", label: "Failed", count: failedOrders.length, icon: XCircle, color: "text-red" },
  ];

  return (
    <div className="space-y-5">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="font-display text-xl font-black text-foreground tracking-tight">Optimize</h2>
          <p className="text-[12px] text-muted-dark mt-1">Rule-based FFD engine — select a box, see savings, view 3D pack</p>
        </div>
        <button
          onClick={async () => {
            setIsRefreshing(true);
            await refetch();
            setIsRefreshing(false);
          }}
          className="flex items-center gap-1.5 rounded-full border border-border px-4 py-2 text-[12px] font-semibold text-muted hover:text-foreground hover:border-border2 transition-all"
        >
          <RefreshCw className={`h-3.5 w-3.5 ${isRefreshing ? "animate-spin" : ""}`} />
          Refresh
        </button>
      </div>

      {/* Status Filter */}
      <div className="flex items-center gap-2 overflow-x-auto pb-1">
        {filterOptions.map((f) => {
          const Icon = f.icon;
          return (
            <button
              key={f.key}
              onClick={() => setStatusFilter(f.key)}
              className={`flex items-center gap-2 rounded-full px-4 py-2 text-[12px] font-semibold transition-all whitespace-nowrap ${
                statusFilter === f.key
                  ? "bg-accent/10 text-accent border border-accent/20 shadow-[0_0_20px_rgba(200,255,0,.05)]"
                  : "bg-surface border border-border text-muted hover:border-border2"
              }`}
            >
              <Icon className={`h-3.5 w-3.5 ${statusFilter === f.key ? f.color : "text-muted-dark"}`} />
              {f.label}
              <span className={`text-[10px] px-1.5 py-0.5 rounded-full ${
                statusFilter === f.key ? "bg-accent/10 text-accent/70" : "bg-ink2 text-muted-dark"
              }`}>
                {f.count}
              </span>
            </button>
          );
        })}
      </div>

      {/* Manual Optimization */}
      {statusFilter === "pending" && (
        <Card gradient glow>
          <div className="space-y-4">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 rounded-lg bg-accent/10 border border-accent/20 flex items-center justify-center">
                <Zap className="h-4 w-4 text-accent" />
              </div>
              <h3 className="text-[14px] font-semibold text-foreground">Run AI Packaging Engine</h3>
            </div>

            <div>
              <label className="mb-2 block text-[11px] font-bold text-muted-dark uppercase tracking-wider">
                Select Order
              </label>
              <select
                value={selectedOrder}
                onChange={(e) => setSelectedOrder(Number(e.target.value))}
                className="w-full rounded-xl border border-border2 bg-surface2 px-4 py-3 text-sm text-foreground outline-none focus:border-accent focus:shadow-[0_0_0_3px_rgba(200,255,0,.08)] transition-all"
              >
                <option value={0}>Choose a pending order...</option>
                {pendingOrders.map((order) => (
                  <option key={order.id} value={order.id}>
                    Order #{order.id} — {order.shipping_zone} ({order.channel ? order.channel + " · " : ""}{order.customer_name || "No customer"})
                  </option>
                ))}
              </select>
            </div>

            {pendingOrders.length === 0 && (
              <div className="rounded-xl bg-border/50 px-4 py-3 text-[13px] text-muted flex items-center gap-2">
                <Info className="h-4 w-4" />
                No pending orders. Upload orders or wait for background optimization to complete.
              </div>
            )}

            <div className="flex items-center gap-3">
              <Button onClick={handleOptimize} disabled={!selectedOrder} loading={optLoading} size="lg">
                <Zap className="h-4 w-4" />
                Run AI packaging engine
              </Button>
              {currentResult && (
                <Button variant="ghost" onClick={handleReset}>
                  <RotateCcw className="h-3.5 w-3.5" />
                  Reset
                </Button>
              )}
            </div>
          </div>
        </Card>
      )}

      {/* Current optimization result */}
      {currentResult && !optLoading && (
        <Card gradient className="border-accent/20">
          <div className="flex items-center gap-2 mb-4">
            <CheckCircle className="h-5 w-5 text-teal" />
            <h3 className="text-[14px] font-semibold text-foreground">Optimization Complete</h3>
            <Badge variant="success">Saved Rs.{currentResult.savings.toFixed(2)}</Badge>
          </div>

          <div className="flex flex-col gap-4 mb-4">
            <Card className="bg-accent/5 border-accent/20 border-l-[4px] border-l-accent relative overflow-hidden">
              <div className="absolute top-0 right-0 w-48 h-48 bg-accent/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/4" />
              <div className="flex items-start justify-between relative z-10">
                <div className="flex items-start gap-4">
                  <div className="w-12 h-12 rounded-xl bg-accent/10 border border-accent/20 flex items-center justify-center flex-shrink-0 mt-1">
                    <Box className="h-6 w-6 text-accent" />
                  </div>
                  <div>
                    <p className="text-[11px] text-muted-dark uppercase tracking-wider font-bold mb-1">Recommended Box</p>
                    <p className="text-[28px] font-black text-accent tracking-tight leading-none mb-2">{currentResult.recommended_box}</p>
                    {currentResult.boxInfo && (
                      <p className="text-[12px] text-muted font-medium">
                        {currentResult.boxInfo.length_cm} × {currentResult.boxInfo.width_cm} × {currentResult.boxInfo.height_cm} cm · Max {currentResult.boxInfo.max_weight_kg}kg
                        {currentResult.boxInfo.supports_fragile && <span className="text-amber-500 font-bold ml-1">· Fragile-safe</span>}
                      </p>
                    )}
                  </div>
                </div>

                <div className="text-right flex flex-col items-center">
                  <div className="inline-flex items-center justify-center w-14 h-14 rounded-full border-[3px] border-accent text-accent shadow-[0_0_15px_rgba(200,255,0,0.2)] bg-accent/10">
                    <span className="text-[16px] font-black leading-none">{(currentResult.efficiency_score * 100).toFixed(0)}%</span>
                  </div>
                  <p className="text-[10px] text-muted-dark font-bold mt-2 uppercase tracking-wider">Efficiency</p>
                </div>
              </div>
            </Card>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
              <Card className="bg-surface2 border-border">
                <div className="flex items-start gap-3">
