                              <Box className="h-5 w-5 text-accent" />
                            </div>
                            <div>
                              <p className="text-[10px] text-muted-dark uppercase tracking-wider font-bold mb-1">Recommended Box</p>
                              <p className="text-[20px] font-black text-accent tracking-tight leading-none mb-1.5">{optResult.recommended_box}</p>
                              {optResult.boxInfo && (
                                <p className="text-[11px] text-muted font-medium">
                                  {optResult.boxInfo.length_cm} × {optResult.boxInfo.width_cm} × {optResult.boxInfo.height_cm} cm · Max {optResult.boxInfo.max_weight_kg}kg
                                  {optResult.boxInfo.supports_fragile && <span className="text-amber-500 font-bold ml-1">· Fragile-safe</span>}
                                </p>
                              )}
                            </div>
                          </div>

                          <div className="text-right flex flex-col items-center">
                            <div className="inline-flex items-center justify-center w-10 h-10 rounded-full border-[2px] border-accent text-accent shadow-[0_0_10px_rgba(200,255,0,0.2)] bg-accent/10">
                              <span className="text-[12px] font-black leading-none">{(optResult.efficiency_score * 100).toFixed(0)}%</span>
                            </div>
                            <p className="text-[9px] text-muted-dark font-bold mt-1.5 uppercase tracking-wider">Efficiency</p>
                          </div>
                        </div>
                      </Card>

                      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                        <Card className="bg-surface2 border-border">
                          <div className="flex items-start gap-3">
                            <TrendingUp className="h-5 w-5 text-teal mt-0.5 flex-shrink-0" />
                            <div className="flex-1 w-full">
                              <p className="text-[10px] text-muted-dark uppercase tracking-wider font-bold mb-3">Cost Analysis</p>
                              <div className="space-y-2">
                                <div className="flex justify-between items-center text-[12px]">
                                  <span className="text-muted">Baseline Cost</span>
                                  <span className="text-muted line-through">Rs.{optResult.baseline_cost.toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between items-center text-[13px] font-semibold">
                                  <span className="text-foreground">Optimized Cost</span>
                                  <span className="text-foreground">Rs.{optResult.optimized_cost.toFixed(2)}</span>
                                </div>
                                <div className="h-px bg-border my-1"></div>
                                {optResult.savings > 0 ? (
                                  <div className="flex justify-between items-center text-[13px] font-bold text-teal">
                                    <span>Total Savings</span>
                                    <span>Rs.{optResult.savings.toFixed(2)}</span>
                                  </div>
                                ) : (
                                  <div className="flex justify-between items-center text-[13px] font-bold text-orange">
                                    <span>Best Fit Only</span>
                                    <span>Rs.0.00</span>
                                  </div>
                                )}
                              </div>
                            </div>
                          </div>
                        </Card>

                        {optResult.decision_explanation && (
                          <Card className="bg-purple/5 border-purple/10">
                            <div className="flex items-start gap-2">
                              <Info className="h-4 w-4 text-purple mt-0.5 flex-shrink-0" />
                              <div>
                                <p className="text-[10px] text-purple/80 uppercase tracking-wider font-bold mb-1.5">Why this box?</p>
                                <p className="text-[12px] text-foreground/80 leading-relaxed font-medium">{optResult.decision_explanation}</p>
                              </div>
                            </div>
                          </Card>
                        )}
                      </div>
                    </div>

                    {/* Packing Order */}
                    {optResult.item_order && optResult.item_order.length > 0 && (
                      <Card>
                        <p className="text-[12px] font-semibold text-foreground mb-3 flex items-center gap-2">
                          <Package className="h-4 w-4 text-accent" />
                          Packing Order (bottom to top)
                        </p>
                        <div className="space-y-2">
                          {optResult.item_order.map((item, i) => (
                            <div key={i} className="flex items-center gap-3 py-2 px-3 rounded-lg bg-ink2/50 border border-border/50">
                              <div className="w-6 h-6 rounded-full bg-accent/10 flex items-center justify-center text-[10px] font-bold text-accent flex-shrink-0">
                                {i + 1}
                              </div>
                              <div className="flex-1">
                                <span className="text-[12px] text-foreground font-medium">{item.product_name}</span>
                                <span className="text-[11px] text-muted ml-1">×{item.quantity}</span>
                              </div>
                              <Badge variant={item.is_fragile ? "danger" : "success"}>
                                {item.layer}
                              </Badge>
                            </div>
                          ))}
                        </div>
                      </Card>
                    )}

                    {/* 3D Viewer */}
                    {optResult.packed_items && optResult.packed_items.length > 0 && (
                      <Card>
                        <div className="flex items-center justify-between mb-4">
                          <div className="flex items-center gap-2">
                            <Rotate3D className="h-4 w-4 text-accent" />
                            <p className="text-[13px] font-semibold text-foreground">3D Packing Visualization</p>
                          </div>
                          <button
                            onClick={() => toggle3D(order.id)}
                            className="flex items-center gap-1.5 rounded-full bg-accent/10 text-accent px-3 py-1.5 text-[11px] font-semibold hover:bg-accent/20 transition-all"
                          >
                            <Rotate3D className="h-3 w-3" />
                            {show3D ? "Hide 3D" : "Show 3D"}
                          </button>
                        </div>
                        {show3D && (
                          <ThreeDPackViewer
                            box={{
                              name: optResult.recommended_box,
                              length_cm: optResult.boxInfo?.length_cm || 45,
                              width_cm: optResult.boxInfo?.width_cm || 35,
                              height_cm: optResult.boxInfo?.height_cm || 25,
                            }}
                            items={optResult.packed_items.map(item => ({
                              product_name: item.product_name,
                              position_x: item.position_x,
                              position_y: item.position_y,
                              position_z: item.position_z,
                              length_cm: item.length_cm || 10,
                              width_cm: item.width_cm || 10,
                              height_cm: item.height_cm || 10,
                              is_fragile: item.is_fragile,
                              quantity: item.quantity,
                            }))}
                          />
                        )}
                      </Card>
                    )}
                  </div>
                )}

                {/* Loading state */}
                {!optResult && order.status !== "pending" && (
                  <div className="mt-4 pt-4 border-t border-border/50 flex items-center gap-2">
                    <Loader2 className="h-3.5 w-3.5 text-accent animate-spin" />
                    <span className="text-[11px] text-muted">Loading optimization details...</span>
                  </div>
                )}
              </Card>
            );
          })}
        </div>
      )}

      {/* Pending orders list */}
      {statusFilter === "pending" && pendingOrders.length > 0 && !currentResult && !optLoading && (
        <Card>
          <div className="text-[13px] font-semibold text-foreground mb-3 flex items-center gap-2">
            <Clock className="h-4 w-4 text-accent" />
            Pending Orders
          </div>
          <div className="space-y-2">
            {pendingOrders.map((order) => (
              <div key={order.id} className="flex items-center justify-between py-3 px-3 rounded-xl bg-ink2/50 border border-border/50 hover:border-border transition-all">
                <div className="flex items-center gap-3">
                  <span className="font-mono text-[12px] text-accent font-semibold">#{order.id}</span>
                  <span className="text-[12px] text-muted">{order.shipping_zone}</span>
                  {order.channel && <Badge variant="purple">{order.channel}</Badge>}
                  {order.customer_name && (
                    <span className="text-[11px] text-muted-dark">{order.customer_name}</span>
                  )}
                </div>
                <button
                  onClick={() => {
                    setSelectedOrder(order.id);
                  }}
                  className="text-[11px] text-accent hover:bg-accent/10 px-3 py-1.5 rounded-full transition-all font-semibold"
                >
                  Select →
                </button>
              </div>
            ))}
          </div>
        </Card>
      )}

      {statusFilter === "pending" && pendingOrders.length === 0 && (
        <EmptyState
          title="No pending orders"
          description="All orders have been optimized. Check the Optimized tab for results."
        />
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { getOrderOptimizationStatus } from "@/services/orders.service";
import type { OptimizationResult } from "@/types";
import Card from "@/components/ui/Card";
import Badge from "@/components/ui/Badge";
import Spinner from "@/components/ui/Spinner";
import {
  TrendingUp, Info, Rotate3D, ArrowRight,
  X, Box, Layers, CheckCircle, AlertTriangle, Zap, Ruler, ShieldAlert, ArrowDownCircle, ArrowUpCircle, Circle
} from "lucide-react";
import dynamic from "next/dynamic";
import api from "@/services/api";

const ThreeDPackViewer = dynamic(
  () => import("@/components/optimization/ThreeDPackViewer"),
  { ssr: false, loading: () => <div className="h-[400px] bg-[#0a0a14] rounded-xl flex items-center justify-center text-gray-500 text-sm border border-border">Loading 3D viewer...</div> }
);

interface BoxInfo {
  name: string;
  length_cm: number;
  width_cm: number;
  height_cm: number;
  max_weight_kg: number;
  supports_fragile: boolean;
}

interface PackNowModalProps {
  orderId: number;
  onClose: () => void;
}

export default function PackNowModal({ orderId, onClose }: PackNowModalProps) {
  const [result, setResult] = useState<OptimizationResult | null>(null);
  const [boxInfo, setBoxInfo] = useState<BoxInfo | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [show3D, setShow3D] = useState(true);

  const hasFragile = result?.item_order?.some(item => item.is_fragile) || false;

  useEffect(() => {
    const fetchData = async () => {
      try {
        const data = await getOrderOptimizationStatus(orderId);
        setResult(data);

        if (data.recommended_box) {
          try {
            const boxes = await api.get("/inventory");
            const box = boxes.data.find((b: BoxInfo) => b.name === data.recommended_box);
            if (box) setBoxInfo(box);
          } catch { /* box not found */ }
        }
      } catch {
        setError("Failed to load optimization data. Please run optimization first.");
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [orderId]);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/70 backdrop-blur-sm" onClick={onClose} />
      <div className="relative w-full max-w-4xl max-h-[90vh] overflow-y-auto bg-ink2 border border-border rounded-2xl shadow-2xl animate-fadeInScale">
        {/* Header */}
        <div className="sticky top-0 z-10 flex items-center justify-between px-6 py-4 bg-ink2/95 backdrop-blur-sm border-b border-border">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 rounded-lg bg-accent/10 border border-accent/20 flex items-center justify-center">
              <Zap className="h-4 w-4 text-accent" />
            </div>
            <div>
              <h3 className="text-[15px] font-bold text-foreground">Pack Now — Order #{orderId}</h3>
              <p className="text-[10px] text-muted-dark">FFD Engine optimization result</p>
            </div>
          </div>
          <button
            onClick={onClose}
            className="w-8 h-8 rounded-lg bg-white/[.04] border border-border flex items-center justify-center text-muted hover:text-foreground hover:bg-white/[.08] transition-all"
          >
            <X className="h-4 w-4" />
          </button>
        </div>

        <div className="p-6 space-y-5">
          {loading && (
            <div className="flex flex-col items-center justify-center py-16">
              <Spinner size="lg" />
              <p className="mt-4 text-sm text-muted">Loading optimization data...</p>
            </div>
          )}

          {error && (
            <Card className="border-red/20 bg-red/5">
              <div className="flex items-start gap-3">
                <AlertTriangle className="h-5 w-5 text-red mt-0.5 flex-shrink-0" />
                <div>
                  <p className="text-[13px] font-semibold text-red">Failed to Load</p>
                  <p className="text-[12px] text-muted mt-1">{error}</p>
                  <button
                    onClick={onClose}
                    className="mt-3 text-[12px] text-accent hover:underline font-semibold"
                  >
                    Close
                  </button>
                </div>
              </div>
            </Card>
          )}

          {result && !loading && (
            <>
              {/* Fragile Alert */}
              {hasFragile && (
                <div className="rounded-xl p-4 border bg-amber-500/10 border-amber-500/30">
                  <div className="flex items-center gap-3">
                    <ShieldAlert className="h-5 w-5 text-amber-500 flex-shrink-0" />
                    <div>
                      <p className="text-[13px] font-bold text-amber-500 uppercase tracking-wide">
                        Fragile Order
                      </p>
                      <p className="text-[12px] text-amber-500/80 mt-0.5 font-medium">
                        Contains delicate items. Pack carefully and add necessary padding. Follow packing instructions strictly.
                      </p>
                    </div>
                  </div>
                </div>
              )}

              {/* Status Banner */}
              <div className={`rounded-xl p-4 border ${
                result.savings > 0
                  ? "bg-teal/5 border-teal/20"
                  : result.savings === 0
                  ? "bg-orange/5 border-orange/20"
                  : "bg-red/5 border-red/20"
              }`}>
                <div className="flex items-center gap-3">
                  {result.savings > 0 ? (
                    <CheckCircle className="h-5 w-5 text-teal flex-shrink-0" />
                  ) : (
                    <AlertTriangle className="h-5 w-5 text-orange flex-shrink-0" />
                  )}
                  <div>
                    <p className={`text-[13px] font-semibold ${
                      result.savings > 0 ? "text-teal" : "text-orange"
                    }`}>
                      {result.savings > 0
                        ? `Optimized — Saved Rs.${result.savings.toFixed(2)}`
                        : "Best fit only — No cost savings possible"
                      }
                    </p>
                    <p className="text-[11px] text-muted mt-0.5">
                      Efficiency: {(result.efficiency_score * 100).toFixed(0)}% space utilization
                    </p>
                  </div>
                </div>
              </div>

              {/* Why This Box */}
              <Card className="border-l-[3px] border-l-accent/30 bg-accent/5">
                <div className="flex items-start gap-3">
                  <Info className="h-5 w-5 text-accent mt-0.5 flex-shrink-0" />
                  <div>
                    <p className="text-[12px] font-bold text-foreground mb-1">Why this box?</p>
                    <p className="text-[12px] text-muted leading-relaxed">
                      {result.decision_explanation || "The FFD engine selected this box as the optimal fit based on volume, weight, and fragility constraints."}
                    </p>
                  </div>
                </div>
              </Card>

              {/* Box Recommendation + Cost */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <Card className="bg-surface2 border-border">
                  <div className="flex items-start gap-3">
                    <Box className="h-5 w-5 text-accent mt-0.5 flex-shrink-0" />
                    <div className="flex-1">
                      <p className="text-[10px] text-muted-dark uppercase tracking-wider font-bold mb-2">Recommended Box</p>
                      <p className="text-[18px] font-bold text-accent">{result.recommended_box}</p>
                      {boxInfo && (
                        <div className="mt-2 flex items-center gap-2 text-[11px] text-muted">
                          <Ruler className="h-3 w-3" />
                          {boxInfo.length_cm} × {boxInfo.width_cm} × {boxInfo.height_cm} cm
                          <span className="text-muted-dark">·</span>
                          Max {boxInfo.max_weight_kg}kg
                          {boxInfo.supports_fragile && (
                            <>
                              <span className="text-muted-dark">·</span>
                              <span className="text-teal">Fragile-safe</span>
                            </>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                </Card>

                <Card className="bg-surface2 border-border">
                  <div className="flex items-start gap-3">
                    <TrendingUp className="h-5 w-5 text-teal mt-0.5 flex-shrink-0" />
                    <div className="flex-1 w-full">
                      <p className="text-[10px] text-muted-dark uppercase tracking-wider font-bold mb-3">Cost Analysis</p>
                      <div className="space-y-2.5">
                        <div className="flex justify-between items-center text-[12px]">
                          <span className="text-muted">Baseline Cost</span>
                          <span className="text-muted line-through">Rs.{result.baseline_cost.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between items-center text-[13px] font-semibold">
                          <span className="text-foreground">Optimized Cost</span>
                          <span className="text-foreground">Rs.{result.optimized_cost.toFixed(2)}</span>
                        </div>
                        <div className="h-px bg-border my-1"></div>
                        {result.savings > 0 ? (
                          <div className="flex justify-between items-center text-[14px] font-bold text-teal">
                            <span>Total Savings</span>
                            <span>Rs.{result.savings.toFixed(2)}</span>
                          </div>
                        ) : (
                          <div className="flex justify-between items-center text-[14px] font-bold text-orange">
                            <span>Best Fit Only</span>
                            <span>Rs.0.00</span>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                </Card>
              </div>

              {/* Packing Instructions */}
              {result.item_order && result.item_order.length > 0 && (
                <Card>
                  <div className="flex items-center gap-2 mb-4">
                    <Layers className="h-4 w-4 text-purple" />
                    <p className="text-[13px] font-semibold text-foreground">How to Pack (bottom to top)</p>
                  </div>
                  <div className="space-y-2">
                    {result.item_order.map((item, i) => (
                      <div key={i} className={`flex items-center gap-3 py-3 px-4 rounded-xl border border-border/50 ${
                        item.is_fragile ? "bg-amber-500/5 border-amber-500/20" : "bg-ink2/50"
                      }`}>
                        <div className="w-8 h-8 rounded-full bg-surface border border-border flex items-center justify-center text-[12px] font-bold text-muted flex-shrink-0">
                          {i + 1}
                        </div>
                        <div className="flex-1 min-w-0">
                          <span className="text-[13px] text-foreground font-semibold block">{item.product_name}</span>
                          <div className="flex items-center gap-2 mt-1">
                            <span className="text-[11px] text-muted bg-surface2 px-1.5 py-0.5 rounded">× {item.quantity} units</span>

                            {item.is_fragile && (
                              <span className="flex items-center gap-1 text-[10px] text-amber-500 font-semibold bg-amber-500/10 px-1.5 py-0.5 rounded border border-amber-500/20">
                                <ShieldAlert className="h-3 w-3" />
                                Add Padding
                              </span>
                            )}
                          </div>
                        </div>

                        <div className="flex items-center">
                          {item.layer === "bottom" && (
                            <div className="flex items-center gap-1.5 text-blue text-[11px] font-semibold bg-blue/10 px-2.5 py-1.5 rounded-lg border border-blue/20">
                              <ArrowDownCircle className="h-3.5 w-3.5" />
                              Heavy (Bottom)
                            </div>
                          )}
                          {item.layer === "middle" && (
                            <div className="flex items-center gap-1.5 text-teal text-[11px] font-semibold bg-teal/10 px-2.5 py-1.5 rounded-lg border border-teal/20">
                              <Circle className="h-3.5 w-3.5" />
                              Standard (Middle)
                            </div>
                          )}
                          {item.layer === "top" && (
                            <div className="flex items-center gap-1.5 text-purple text-[11px] font-semibold bg-purple/10 px-2.5 py-1.5 rounded-lg border border-purple/20">
                              <ArrowUpCircle className="h-3.5 w-3.5" />
                              Light (Top)
                            </div>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                </Card>
              )}

              {/* 3D Pack View */}
              {result.packed_items && result.packed_items.length > 0 && (
                <Card>
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-2">
                      <Rotate3D className="h-4 w-4 text-accent" />
                      <p className="text-[13px] font-semibold text-foreground">Pack 3D View</p>
                      <Badge variant="warning">Interactive</Badge>
                    </div>
                    <div className="flex items-center gap-2">
                      <button
                        onClick={() => setShow3D(!show3D)}
                        className="flex items-center gap-1.5 rounded-full bg-accent/10 text-accent px-3 py-1.5 text-[11px] font-semibold hover:bg-accent/20 transition-all"
                      >
                        <Rotate3D className="h-3 w-3" />
                        {show3D ? "Close 3D" : "Open 3D"}
                      </button>
                    </div>
                  </div>

                  {show3D && (
                    <ThreeDPackViewer
                      box={{
                        name: result.recommended_box,
                        length_cm: boxInfo?.length_cm || 45,
                        width_cm: boxInfo?.width_cm || 35,
                        height_cm: boxInfo?.height_cm || 25,
                      }}
                      items={result.packed_items.map(item => ({
                        product_name: item.product_name,
                        position_x: item.position_x,
                        position_y: item.position_y,
                        position_z: item.position_z,
                        length_cm: item.length_cm || 10,
                        width_cm: item.width_cm || 10,
                        height_cm: item.height_cm || 10,
                        is_fragile: item.is_fragile,
                        quantity: item.quantity,
                      }))}
                    />
                  )}

                  {!show3D && (
                    <div className="flex flex-col items-center justify-center py-12 bg-ink2/50 rounded-xl border border-border/50 border-dashed">
                      <Rotate3D className="h-10 w-10 text-muted-dark mb-3" />
                      <p className="text-[13px] text-muted font-medium">Click &quot;Open 3D&quot; to view the interactive 3D pack</p>
                      <p className="text-[11px] text-muted-dark mt-1">Rotate 360° · See exact box dimensions · Zoom in/out</p>
                    </div>
                  )}
                </Card>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import Link from "next/link";
import { Order, OrderOptimizationSummary } from "@/types";
import Badge from "@/components/ui/Badge";
import { formatDate } from "@/lib/utils";
import { Zap, Eye, Store, MapPin, CreditCard, Package, AlertTriangle } from "lucide-react";

interface OrdersTableProps {
  orders: Order[];
  summaries?: Map<number, OrderOptimizationSummary>;
  onOptimize?: (id: number) => void;
  onPackNow?: (id: number) => void;
}

const statusVariant: Record<string, "warning" | "success" | "danger" | "info" | "purple"> = {
  pending: "warning",
  optimized: "success",
  failed: "danger",
  no_savings: "info",
};

const channelColors: Record<string, string> = {
  shopify: "bg-green-500/10 text-green-400 border-green-500/20",
  amazon: "bg-orange-500/10 text-orange-400 border-orange-500/20",
  flipkart: "bg-blue-500/10 text-blue-400 border-blue-500/20",
  meesho: "bg-yellow-500/10 text-yellow-400 border-yellow-500/20",
  delhivery: "bg-purple-500/10 text-purple-400 border-purple-500/20",
  unicommerce: "bg-cyan-500/10 text-cyan-400 border-cyan-500/20",
};

export default function OrdersTable({ orders, summaries, onOptimize, onPackNow }: OrdersTableProps) {
  if (orders.length === 0) {
    return (
      <div className="rounded-2xl border border-border bg-surface p-12 text-center">
        <Package className="h-10 w-10 mx-auto text-muted-dark mb-3" />
        <p className="text-sm text-muted">No orders found</p>
      </div>
    );
  }

  return (
    <div className="overflow-hidden rounded-2xl border border-border bg-surface">
      <div className="overflow-x-auto">
        <table className="w-full text-left text-sm">
          <thead>
            <tr className="border-b border-border bg-ink2/50">
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Order</th>
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Channel</th>
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Customer</th>
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Location</th>
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Pincode</th>
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Payment</th>
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Status</th>
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Box</th>
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Savings</th>
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Fragile</th>
              <th className="px-4 py-3.5 text-[10px] font-bold text-muted-dark uppercase tracking-wider">Actions</th>
            </tr>
          </thead>
          <tbody>
            {orders.map((order, idx) => (
              <tr key={order.id} className={`border-b border-border/50 table-row-hover transition-colors ${
                idx % 2 === 0 ? "bg-transparent" : "bg-white/[.01]"
              }`}>
                <td className="px-4 py-3.5">
                  <div className="font-mono text-[12px] text-accent font-semibold">#{order.id}</div>
                  {order.channel_order_id && (
                    <div className="text-[10px] text-muted-dark mt-0.5">{order.channel_order_id}</div>
                  )}
                </td>
                <td className="px-4 py-3.5">
                  {order.channel ? (
                    <span className={`inline-flex items-center gap-1.5 px-2 py-0.5 rounded-full text-[10px] font-semibold border ${
                      channelColors[order.channel.toLowerCase()] || "bg-surface2 text-muted border-border"
                    }`}>
                      <Store className="h-2.5 w-2.5" />
                      <span className="capitalize">{order.channel}</span>
                    </span>
                  ) : (
                    <span className="text-[12px] text-muted-dark">—</span>
                  )}
                </td>
                <td className="px-4 py-3.5">
                  {order.customer_name ? (
                    <div>
                      <div className="text-[12px] text-foreground font-medium">{order.customer_name}</div>
                      {order.customer_phone && (
                        <div className="text-[10px] text-muted-dark mt-0.5">{order.customer_phone}</div>
                      )}
                    </div>
                  ) : (
                    <span className="text-[12px] text-muted-dark">—</span>
                  )}
                </td>
                <td className="px-4 py-3.5">
                  {order.customer_city ? (
                    <div className="flex items-center gap-1.5">
                      <MapPin className="h-3 w-3 text-muted-dark flex-shrink-0" />
                      <div>
                        <div className="text-[12px] text-foreground">{order.customer_city}</div>
                        {order.customer_state && (
                          <div className="text-[10px] text-muted-dark">{order.customer_state}</div>
                        )}
                      </div>
                    </div>
                  ) : (
                    <span className="text-[12px] text-muted-dark">—</span>
                  )}
                </td>
                <td className="px-4 py-3.5">
                  <span className="font-mono text-[12px] text-foreground bg-ink2 px-2 py-0.5 rounded">{order.customer_pincode || "—"}</span>
                </td>
                <td className="px-4 py-3.5">
                  {order.payment_type ? (
                    <div className="flex items-center gap-1.5">
                      <CreditCard className="h-3 w-3 text-muted-dark" />
                      <span className="text-[12px] text-foreground capitalize">{order.payment_type}</span>
                    </div>
                  ) : (
                    <span className="text-[12px] text-muted-dark">—</span>
                  )}
                </td>
                <td className="px-4 py-3.5">
                  <Badge variant={statusVariant[order.status] || "default"}>
                    {order.status}
                  </Badge>
                </td>
                <td className="px-4 py-3.5">
                  {summaries?.get(order.id)?.recommended_box ? (
                    <span className="text-[12px] text-accent font-semibold">{summaries.get(order.id)!.recommended_box}</span>
                  ) : (
                    <span className="text-[12px] text-muted-dark">—</span>
                  )}
                </td>
                <td className="px-4 py-3.5">
                  {summaries?.get(order.id) && summaries.get(order.id)!.savings > 0 ? (
                    <span className="text-[12px] text-teal font-semibold">+Rs.{summaries.get(order.id)!.savings.toFixed(2)}</span>
                  ) : (
                    <span className="text-[12px] text-muted-dark">—</span>
                  )}
                </td>
                <td className="px-4 py-3.5">
                  {summaries?.get(order.id)?.has_fragile ? (
                    <AlertTriangle className="h-4 w-4 text-amber-500" />
                  ) : (
                    <span className="text-[12px] text-muted-dark">—</span>
                  )}
                </td>
                <td className="px-4 py-3.5">
                  <div className="flex items-center gap-1.5">
                    <Link
                      href={`/orders/${order.id}`}
                      className="flex items-center gap-1 text-[11px] text-muted hover:text-foreground transition-colors px-2 py-1.5 rounded-lg hover:bg-white/[.04]"
                    >
                      <Eye className="h-3.5 w-3.5" />
                      View
                    </Link>
                    {order.status === "pending" && onOptimize && (
                      <button
                        onClick={() => onOptimize(order.id)}
                        className="flex items-center gap-1 text-[11px] text-accent hover:text-accent/80 transition-colors font-semibold px-2 py-1.5 rounded-lg hover:bg-accent/5"
                      >
                        <Zap className="h-3.5 w-3.5" />
                        Optimize
                      </button>
                    )}
                    {(order.status === "optimized" || order.status === "no_savings") && onPackNow && (
                      <button
                        onClick={() => onPackNow(order.id)}
                        className="flex items-center gap-1 text-[11px] text-teal hover:text-teal/80 transition-colors font-semibold px-3 py-1.5 rounded-lg bg-teal/10 hover:bg-teal/20 ml-1"
                      >
                        <Package className="h-3.5 w-3.5" />
                        Pack Now
                      </button>
                    )}
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
